  public initializeStateVector(qubits: number, initialState: string = 'zero'): StateVector {
    const dim = Math.pow(2, qubits);
    const amplitudes = Array(dim).fill(0);
    if (initialState === 'zero') amplitudes[0] = 1;
    else if (initialState === 'plus') {
      const val = 1 / Math.sqrt(dim);
      for (let i = 0; i < dim; i++) amplitudes[i] = val;
    } else if (initialState === 'random') {
      for (let i = 0; i < dim; i++) amplitudes[i] = Math.random() - 0.5;
      const norm = Math.sqrt(amplitudes.reduce((s, v) => s + v * v, 0));
      for (let i = 0; i < dim; i++) amplitudes[i] /= norm;
    }
    const sv: StateVector = { amplitudes, qubits, timestamp: Date.now() };
    this._stateVectors.push(sv);
    this._recordHistory(`initializeStateVector(${qubits}, ${initialState})`);
    return sv;
  }

