    const dim = Math.pow(2, qubits);
    const matrix: number[][] = Array.from({ length: dim }, (_, i) =>
      Array.from({ length: dim }, (_, j) => (i === j ? (i === 0 ? 1 : 0) : 0))
    );
    const dm: DensityMatrix = { matrix, qubits, purity: 1 };
