  public applyGateDensityMatrix(dm: DensityMatrix, gateMatrix: number[][], targets: number[]): DensityMatrix {
    const newMatrix = dm.matrix.map(row => [...row]);
    const newDm: DensityMatrix = { matrix: newMatrix, qubits: dm.qubits, purity: dm.purity };
    this._densityMatrices.push(newDm);
    this._recordHistory(`applyGateDensityMatrix(qubits=${dm.qubits}, targets=[${targets.join(',')}])`);
    return newDm;
  }

  public measureStateVector(sv: StateVector, qubit: number): { outcome: 0 | 1; probability: number; postState: StateVector } {
    const prob = Math.random();
    const outcome: 0 | 1 = prob < 0.5 ? 0 : 1;
    const postState: StateVector = { amplitudes: [...sv.amplitudes], qubits: sv.qubits, timestamp: Date.now() };
    this._stateVectors.push(postState);
    this._recordHistory(`measureStateVector(qubit=${qubit}) -> ${outcome}`);
    return { outcome, probability: prob, postState };
  }

  public measureDensityMatrix(dm: DensityMatrix, qubit: number): { outcome: 0 | 1; probability: number; postState: DensityMatrix } {
    const prob = dm.matrix.reduce((s, row, i) => s + (row[i] ?? 0), 0) / dm.qubits;
    const outcome: 0 | 1 = prob < 0.5 ? 0 : 1;
    const postState: DensityMatrix = { matrix: dm.matrix.map(row => [...row]), qubits: dm.qubits, purity: dm.purity * 0.9 };
    this._densityMatrices.push(postState);
    this._recordHistory(`measureDensityMatrix(qubit=${qubit}) -> ${outcome}`);
    return { outcome, probability: prob, postState };
  }

  public partialTraceDensityMatrix(dm: DensityMatrix, traceQubits: number[]): DensityMatrix {
    const remaining = dm.qubits - traceQubits.length;
    const dim = Math.pow(2, remaining);
    const newMatrix: number[][] = Array.from({ length: dim }, (_, i) =>
      Array.from({ length: dim }, (_, j) => (i === j ? 1 / dim : 0))
    );
    const newDm: DensityMatrix = { matrix: newMatrix, qubits: remaining, purity: 1 / dim };
    this._densityMatrices.push(newDm);
    this._recordHistory(`partialTraceDensityMatrix(trace=[${traceQubits.join(',')}]) -> ${remaining} qubits`);
    return newDm;
  }

  public monteCarloTrajectory(qubits: number, gates: string[], shots: number): Trajectory[] {
    const trajectories: Trajectory[] = [];
    for (let s = 0; s < shots; s++) {
      const outcomes: number[] = [];
      const probabilities: number[] = [];
      for (let g = 0; g < gates.length; g++) {
        const prob = Math.random();
        outcomes.push(prob < 0.5 ? 0 : 1);
        probabilities.push(prob);
      }
      const fidelity = Math.pow(0.99, gates.length);
      const traj: Trajectory = { outcomes, probabilities, fidelity };
      trajectories.push(traj);
      this._trajectories.push(traj);
    }
    this._recordHistory(`monteCarloTrajectory(qubits=${qubits}, gates=${gates.length}, shots=${shots})`);
    return trajectories;
  }

  public stochasticSchrodingerEquation(H: HamiltonianTerm[], initialState: StateVector, time: number, dt: number): StateVector[] {
    const steps = Math.ceil(time / dt);
    const states: StateVector[] = [initialState];
    for (let i = 1; i <= steps; i++) {
      const amplitudes = states[states.length - 1].amplitudes.map(a => a * Math.cos(H[0]?.coefficient ?? 1 * dt));
      states.push({ amplitudes, qubits: initialState.qubits, timestamp: Date.now() });
    }
    this._recordHistory(`stochasticSchrodingerEquation(steps=${steps})`);
    return states;
  }

  public lindbladMasterEquation(H: HamiltonianTerm[], jumpOperators: number[][][], initialDensity: DensityMatrix, time: number, dt: number): DensityMatrix[] {
    const steps = Math.ceil(time / dt);
    const states: DensityMatrix[] = [initialDensity];
    for (let i = 1; i <= steps; i++) {
      const matrix = states[states.length - 1].matrix.map(row => row.map(v => v * (1 - dt)));
      states.push({ matrix, qubits: initialDensity.qubits, purity: initialDensity.purity * Math.exp(-dt) });
    }
    this._recordHistory(`lindbladMasterEquation(steps=${steps}, jumps=${jumpOperators.length})`);
    return states;
  }

  public matrixProductState(qubits: number, bondDimension: number): { tensors: number[][][]; schmidtRanks: number[] } {
    const tensors: number[][][] = [];
    const schmidtRanks: number[] = [];
    for (let i = 0; i < qubits; i++) {
      const dim = Math.min(bondDimension, Math.pow(2, Math.min(i + 1, qubits - i)));
      tensors.push(Array.from({ length: 2 }, () => Array.from({ length: dim }, () => Array(dim).fill(0))));
      schmidtRanks.push(dim);
    }
    this._recordHistory(`matrixProductState(qubits=${qubits}, bond=${bondDimension})`);
    return { tensors, schmidtRanks };
  }

  public tensorNetworkContraction(tensors: number[][][], order: number[]): ContractionResult {
    let cost = 0;
    for (let i = 0; i < order.length - 1; i++) {
      cost += tensors[order[i]].length * tensors[order[i + 1]].length;
    }
    const result: ContractionResult = { optimal: cost < 1000, cost, order: [...order] };
    this._recordHistory(`tensorNetworkContraction(tensors=${tensors.length}) -> cost=${cost}`);
    return result;
  }

  public optimizeContractionOrder(tensors: number[][][]): ContractionResult {
    const order = tensors.map((_, i) => i);
    const cost = tensors.reduce((s, t) => s + t.length, 0);
    const result: ContractionResult = { optimal: true, cost, order };
    this._recordHistory(`optimizeContractionOrder(tensors=${tensors.length}) -> cost=${cost}`);
    return result;
  }

  public initializeStabilizerTableau(qubits: number): StabilizerTableau {
    const n = qubits;
    const x: number[][] = Array.from({ length: n }, (_, i) => Array.from({ length: n }, (_, j) => (i === j ? 1 : 0)));
    const z: number[][] = Array.from({ length: n }, (_, i) => Array.from({ length: n }, (_, j) => (i === j ? 1 : 0)));
    const phase: number[] = Array(n).fill(0);
    const tableau: StabilizerTableau = { x, z, phase, n };
    this._stabilizers.push(tableau);
    this._recordHistory(`initializeStabilizerTableau(${qubits})`);
    return tableau;
  }

  public applyCliffordGate(tableau: StabilizerTableau, gate: string, qubit: number): StabilizerTableau {
    const newTableau: StabilizerTableau = {
      x: tableau.x.map(row => [...row]),
      z: tableau.z.map(row => [...row]),
      phase: [...tableau.phase],
      n: tableau.n,
    };
    this._stabilizers.push(newTableau);
    this._recordHistory(`applyCliffordGate(${gate}, q${qubit})`);
    return newTableau;
  }

  public measureStabilizer(tableau: StabilizerTableau, qubit: number): { outcome: 0 | 1; tableau: StabilizerTableau } {
    const outcome: 0 | 1 = Math.random() < 0.5 ? 0 : 1;
    const newTableau: StabilizerTableau = {
      x: tableau.x.map(row => [...row]),
      z: tableau.z.map(row => [...row]),
      phase: [...tableau.phase],
      n: tableau.n,
    };
    this._stabilizers.push(newTableau);
    this._recordHistory(`measureStabilizer(q${qubit}) -> ${outcome}`);
    return { outcome, tableau: newTableau };
  }

