  public initializeStabilizerTableau(qubits: number): StabilizerTableau {
    const n = qubits;
    const x: number[][] = Array.from({ length: n }, (_, i) => Array.from({ length: n }, (_, j) => (i === j ? 1 : 0)));
    const z: number[][] = Array.from({ length: n }, (_, i) => Array.from({ length: n }, (_, j) => (i === j ? 1 : 0)));
    const phase: number[] = Array(n).fill(0);
    const tableau: StabilizerTableau = { x, z, phase, n };
    this._stabilizers.push(tableau);
    this._recordHistory(`initializeStabilizerTableau(${qubits})`);
    return tableau;
  }

  public applyCliffordGate(tableau: StabilizerTableau, gate: string, qubit: number): StabilizerTableau {
    const newTableau: StabilizerTableau = {
      x: tableau.x.map(row => [...row]),
      z: tableau.z.map(row => [...row]),
      phase: [...tableau.phase],
      n: tableau.n,
    };
    this._stabilizers.push(newTableau);
    this._recordHistory(`applyCliffordGate(${gate}, q${qubit})`);
    return newTableau;
  }

  public measureStabilizer(tableau: StabilizerTableau, qubit: number): { outcome: 0 | 1; tableau: StabilizerTableau } {
    const outcome: 0 | 1 = Math.random() < 0.5 ? 0 : 1;
    const newTableau: StabilizerTableau = {
      x: tableau.x.map(row => [...row]),
      z: tableau.z.map(row => [...row]),
      phase: [...tableau.phase],
      n: tableau.n,
    };
    this._stabilizers.push(newTableau);
    this._recordHistory(`measureStabilizer(q${qubit}) -> ${outcome}`);
    return { outcome, tableau: newTableau };
  }

  public destabilizerGroup(tableau: StabilizerTableau): { generators: string[]; rank: number } {
    const generators = Array.from({ length: tableau.n }, (_, i) => `g_${i}`);
    this._recordHistory(`destabilizerGroup(n=${tableau.n}) -> rank=${tableau.n}`);
    return { generators, rank: tableau.n };
  }

  public checkCommutation(tableau1: StabilizerTableau, tableau2: StabilizerTableau): boolean {
    const commute = tableau1.n === tableau2.n;
    this._recordHistory(`checkCommutation() -> ${commute}`);
    return commute;
  }

  public sampleStateVector(sv: StateVector, shots: number): { counts: Map<number, number>; probabilities: number[] } {
    const counts = new Map<number, number>();
    for (let i = 0; i < shots; i++) {
      const outcome = Math.floor(Math.random() * sv.amplitudes.length);
      counts.set(outcome, (counts.get(outcome) ?? 0) + 1);
    }
    const probabilities = sv.amplitudes.map(a => a * a);
    this._recordHistory(`sampleStateVector(shots=${shots})`);
    return { counts, probabilities };
  }

  public fullAmplitudeSimulation(qubits: number, circuitDepth: number): { amplitudes: number[]; runtime: number; memory: number } {
    const dim = Math.pow(2, qubits);
    const amplitudes = Array.from({ length: dim }, () => 1 / Math.sqrt(dim));
    const runtime = dim * circuitDepth * 0.001;
    const memory = dim * dim * 8;
    this._recordHistory(`fullAmplitudeSimulation(qubits=${qubits}, depth=${circuitDepth})`);
    return { amplitudes, runtime, memory };
  }

  public samplingSimulation(qubits: number, circuitDepth: number, shots: number): { samples: number[]; runtime: number; memory: number } {
    const samples = Array.from({ length: shots }, () => Math.floor(Math.random() * Math.pow(2, qubits)));
    const runtime = shots * circuitDepth * 0.0001;
    const memory = Math.pow(2, qubits) * 8;
    this._recordHistory(`samplingSimulation(qubits=${qubits}, shots=${shots})`);
    return { samples, runtime, memory };
  }

  public tensorNetworkSimulation(qubits: number, circuitDepth: number, maxBond: number): { fidelity: number; runtime: number; maxSchmidtRank: number } {
    const fidelity = Math.exp(-qubits / maxBond);
    const runtime = qubits * circuitDepth * maxBond * maxBond * 0.001;
    const maxSchmidtRank = maxBond;
    this._recordHistory(`tensorNetworkSimulation(qubits=${qubits}, depth=${circuitDepth}, maxBond=${maxBond})`);
    return { fidelity, runtime, maxSchmidtRank };
  }

  public stabilizerSimulation(qubits: number, cliffordGates: string[]): { tableau: StabilizerTableau; runtime: number; memory: number } {
    const tableau = this.initializeStabilizerTableau(qubits);
    const runtime = qubits * qubits * cliffordGates.length * 0.0001;
    const memory = qubits * qubits * 8;
    this._recordHistory(`stabilizerSimulation(qubits=${qubits}, gates=${cliffordGates.length})`);
    return { tableau, runtime, memory };
  }

  public addNoiseChannel(type: string, operators: number[][][], rate: number): NoiseChannel {
    const channel: NoiseChannel = { type, operators, rate };
    this._noiseChannels.push(channel);
    this._recordHistory(`addNoiseChannel(${type}, rate=${rate.toExponential(2)})`);
    return channel;
  }

  public applyNoise(state: DensityMatrix, channel: NoiseChannel): DensityMatrix {
    const matrix = state.matrix.map(row => row.map(v => v * (1 - channel.rate)));
    const newState: DensityMatrix = { matrix, qubits: state.qubits, purity: state.purity * (1 - channel.rate) };
    this._densityMatrices.push(newState);
    this._recordHistory(`applyNoise(${channel.type}) -> purity=${newState.purity.toFixed(4)}`);
    return newState;
  }

